function greet(name: string) {
  console.log("Hello, " + name.toUpperCase());
}

greet(null); // Error: Argument of type 'null' is not assignable to parameter of type 'string'.

function greet(name: string | null) {
  if (name) {
    console.log("Hello, " + name.toUpperCase());
  } else {
    console.log("Hello, guest!");
  }
}

greet(null); // Output: Hello, guest!

function getFirstChar(str: string | null | undefined) {
  // Return the first character or a default value
  return str?.charAt(0) ?? '-';
}

console.log(getFirstChar("TypeScript")); // Output: T
console.log(getFirstChar(null));        // Output: -
console.log(getFirstChar(undefined));   // Output: -

